<?php
namespace Tests\Unit\Domain\Hunts;use App\Domain\Hunts\EncounterSizeSelector;use App\Domain\Hunts\Exceptions\NoActiveEncounterSizeException;use App\Domain\Random\RandomNumberGenerator;use InvalidArgumentException;use PHPUnit\Framework\TestCase;class SizeSequenceRandom implements RandomNumberGenerator{public $values;public $calls=0;public function __construct(array $values){$this->values=$values;}public function randomInt(int $min,int $max):int{$this->calls++;return array_shift($this->values);}}class EncounterSizeSelectorTest extends TestCase{public function test_exact_weight_boundaries_and_one_roll(){$rng=new SizeSequenceRandom([80]);$selector=new EncounterSizeSelector($rng);$rows=[['enemy_count'=>1,'weight'=>80,'is_active'=>true],['enemy_count'=>2,'weight'=>17,'is_active'=>true],['enemy_count'=>3,'weight'=>3,'is_active'=>true]];$this->assertSame(1,$selector->select($rows));$this->assertSame(1,$rng->calls);$this->assertSame(2,(new EncounterSizeSelector(new SizeSequenceRandom([81])))->select($rows));$this->assertSame(3,(new EncounterSizeSelector(new SizeSequenceRandom([100])))->select($rows));}public function test_single_config_consumes_one_roll_and_inactive_is_ignored(){$rng=new SizeSequenceRandom([1]);$this->assertSame(2,(new EncounterSizeSelector($rng))->select([['enemy_count'=>9,'weight'=>1,'is_active'=>false],['enemy_count'=>2,'weight'=>5,'is_active'=>true]]));$this->assertSame(1,$rng->calls);}public function test_absence_duplicate_invalid_limit_and_overflow_are_rejected(){$cases=[[],[['enemy_count'=>1,'weight'=>1,'is_active'=>true],['enemy_count'=>1,'weight'=>2,'is_active'=>true]],[['enemy_count'=>0,'weight'=>1,'is_active'=>true]],[['enemy_count'=>11,'weight'=>1,'is_active'=>true]],[['enemy_count'=>1,'weight'=>0,'is_active'=>true]],[['enemy_count'=>1,'weight'=>PHP_INT_MAX,'is_active'=>true],['enemy_count'=>2,'weight'=>1,'is_active'=>true]]];foreach($cases as $i=>$case){try{(new EncounterSizeSelector(new SizeSequenceRandom([1])))->select($case);$this->fail('Expected invalid case '.$i);}catch(NoActiveEncounterSizeException $e){$this->assertSame(0,$i);}catch(InvalidArgumentException $e){$this->assertGreaterThan(0,$i);}}}}
